// src/modules/supply/services/folvyPdfFont.ts
//
// Tipografía de marca Folvy (Fraunces) incrustada para los PDFs.
// Subconjunto latino (Regular 400 + SemiBold 600), convertido a TTF y base64.
// Fuente: Fraunces (Undercase Type), licencia SIL OFL 1.1 — libre para incrustar.
//
// jsPDF no trae Fraunces de serie (solo helvetica/times/courier). Aquí la
// añadimos al Virtual File System del documento y la registramos como familia
// "Fraunces" con estilos normal/bold. Uso en el PDF:
//   ensureFraunces(doc); doc.setFont('Fraunces', 'bold')
// Fraunces es serif DISPLAY: ideal para titulares (nombre de empresa, "PEDIDO
// DE COMPRA", TOTAL). El cuerpo/tabla sigue en helvetica por legibilidad a
// tamaño pequeño (decisión tipográfica, no limitación).

import type jsPDF from 'jspdf'

const FRAUNCES_REGULAR_B64 = ''
const FRAUNCES_SEMIBOLD_B64 = ''

let registeredFor: WeakSet<object> = new WeakSet()

/** Registra Fraunces (normal+bold) en el documento si aún no lo está. Idempotente por doc. */
export function ensureFraunces(doc: jsPDF): void {
  if (registeredFor.has(doc as unknown as object)) return
  try {
    doc.addFileToVFS('Fraunces-Regular.ttf', FRAUNCES_REGULAR_B64)
    doc.addFont('Fraunces-Regular.ttf', 'Fraunces', 'normal')
    doc.addFileToVFS('Fraunces-SemiBold.ttf', FRAUNCES_SEMIBOLD_B64)
    doc.addFont('Fraunces-SemiBold.ttf', 'Fraunces', 'bold')
    registeredFor.add(doc as unknown as object)
  } catch {
    // Si por lo que sea falla la incrustación, el PDF cae a la fuente por
    // defecto sin romperse (el llamador usa setFont con fallback).
  }
}
